import Foundation

enum Secrets {
    
    enum SecretError: Error, LocalizedError {
        case missingKey(String)
        
        var errorDescription: String? {
            switch self {
            case .missingKey(let key):
                return "Missing configuration key: \(key). Ensure Config.xcconfig is properly set up."
            }
        }
    }
    
    static func value(for key: String) throws -> String {
        guard let value = Bundle.main.infoDictionary?[key] as? String, !value.isEmpty else {
            throw SecretError.missingKey(key)
        }
        return value
    }
    
    static var googleMapsAPIKey: String {
        do {
            return try value(for: "GOOGLE_MAPS_API_KEY")
        } catch {
            fatalError("Google Maps API Key not configured: \(error.localizedDescription)")
        }
    }
    
    static var stripePublishableKey: String {
        do {
            return try value(for: "STRIPE_PUBLISHABLE_KEY")
        } catch {
            fatalError("Stripe Publishable Key not configured: \(error.localizedDescription)")
        }
    }
}

