import Foundation
import CoreLocation

struct ServiceLocation {
    let id: String
    let name: String
    let description: String
    let coordinate: CLLocationCoordinate2D
    let priceInCents: Int
    let category: ServiceCategory
    
    var formattedPrice: String {
        let dollars = Double(priceInCents) / 100.0
        return String(format: "$%.2f", dollars)
    }
}

enum ServiceCategory: String, CaseIterable {
    case restaurant = "Restaurant"
    case delivery = "Delivery"
    case rideshare = "Rideshare"
    case experience = "Experience"
    
    var icon: String {
        switch self {
        case .restaurant: return "fork.knife"
        case .delivery: return "box.truck"
        case .rideshare: return "car.fill"
        case .experience: return "star.fill"
        }
    }
    
    var color: UIColor {
        switch self {
        case .restaurant: return .systemOrange
        case .delivery: return .systemBlue
        case .rideshare: return .systemGreen
        case .experience: return .systemPurple
        }
    }
}

